/** Standard "do not edit" banner written at the top of every generated Go file. */
export const GENERATED_BANNER =
  "// Code generated by @openmeter/typespec-go. DO NOT EDIT.";

/**
 * String builder for Go file contents.
 *
 * Each generator builds a single Go file by calling helpers on a Writer:
 *   const w = new Writer();
 *   w.line("package components");
 *   w.blankLine();
 *   w.import("encoding/json");
 *   w.line(`type Foo struct {`);
 *   w.indent(() => { w.line("Bar string") });
 *   w.line("}");
 *   return w.finish();
 *
 * Imports are collected separately and emitted in a sorted import block
 * inserted at the top of the file after `package <name>`.
 */
export class Writer {
  private readonly _lines: string[] = [];
  private readonly _imports = new Set<string>();
  private readonly _preamble: string[] = [];
  private _indent = 0;
  private _packageName?: string;

  /** Set the Go package name. Required: must be called before `finish()`. */
  packageName(name: string): void {
    this._packageName = name;
  }

  /**
   * Lines emitted at the very top of the file, before `package <name>`.
   * Use for the "Code generated by ... DO NOT EDIT." banner so it lands
   * where `go vet` / IDEs expect it.
   */
  preamble(line: string): void {
    this._preamble.push(line);
  }

  /** Register an import. Path is the canonical Go import path. */
  import(path: string): void {
    this._imports.add(path);
  }

  /** Emit a line of text at the current indent. */
  line(text: string): void {
    if (text === "") {
      this._lines.push("");
      return;
    }
    this._lines.push("\t".repeat(this._indent) + text);
  }

  /** Emit a blank line. */
  blankLine(): void {
    this._lines.push("");
  }

  /** Emit a doc comment, with a leading // on each non-empty line. */
  doc(doc: string | undefined): void {
    if (!doc) return;
    for (const ln of doc.split("\n")) {
      this.line(`// ${ln}`.trimEnd());
    }
  }

  /** Indent inside a block; auto-dedents when fn returns. */
  indent(fn: () => void): void {
    this._indent++;
    try {
      fn();
    } finally {
      this._indent--;
    }
  }

  /** Emit `prefix {` … `}` with body indented one level. */
  block(prefix: string, body: () => void, suffix: string = ""): void {
    this.line(`${prefix} {`);
    this.indent(body);
    this.line(`}${suffix}`);
  }

  /**
   * Finalize and return the file contents. Inserts a sorted import block
   * after the package declaration. Does not run gofmt — that's the caller's job.
   */
  finish(): string {
    if (!this._packageName) {
      throw new Error("Writer.finish(): packageName() was never called");
    }
    const out: string[] = [];
    if (this._preamble.length > 0) {
      out.push(...this._preamble);
      out.push("");
    }
    out.push(`package ${this._packageName}`);
    out.push("");
    if (this._imports.size > 0) {
      const sorted = sortImports([...this._imports]);
      if (sorted.length === 1) {
        out.push(`import "${sorted[0]}"`);
      } else {
        out.push("import (");
        // Two groups: stdlib first (no dot in first path segment), then external.
        const std: string[] = [];
        const ext: string[] = [];
        for (const p of sorted) {
          if (!p.includes(".")) std.push(p);
          else ext.push(p);
        }
        if (std.length > 0) {
          for (const p of std) out.push(`\t"${p}"`);
        }
        if (std.length > 0 && ext.length > 0) out.push("");
        for (const p of ext) out.push(`\t"${p}"`);
        out.push(")");
      }
      out.push("");
    }
    out.push(...this._lines);
    let body = out.join("\n");
    if (!body.endsWith("\n")) body += "\n";
    return body;
  }
}

function sortImports(paths: string[]): string[] {
  // Stdlib (no dot) before external; alphabetical within each group.
  return paths.sort((a, b) => {
    const aStd = !a.includes(".");
    const bStd = !b.includes(".");
    if (aStd !== bStd) return aStd ? -1 : 1;
    return a < b ? -1 : a > b ? 1 : 0;
  });
}
